from collections import defaultdict, Counter

def detect_tool_loops(runner_trace):
    tool_calls = []
    handoffs = []

    for step in runner_trace.steps:
        if hasattr(step, 'tool_calls'):
            tool_calls.extend([tc.name for tc in step.tool_calls])
        if hasattr(step, 'handoff_to'):
            handoffs.append(step.handoff_to.agent_id)

    tool_counter = Counter(tool_calls[-10:])
    handoff_counter = Counter(handoffs[-10:])

    loops = []
    for tool, count in tool_counter.items():
        if count >= 5:
            loops.append({'type': 'tool_loop', 'tool': tool, 'count': count})

    for agent_id, count in handoff_counter.items():
        if count >= 3:
            loops.append({'type': 'handoff_loop', 'agent_id': agent_id, 'count': count})

    return loops

import functools
from openai_agents import Runner

class LoopDetector:
    def __init__(self):
        self.tool_history = []
        self.handoff_history = []
        self.max_calls = 5

    def monitor_step(self, step):
        if hasattr(step, 'tool_calls'):
            for tc in step.tool_calls:
                self.tool_history.append(tc.name)
                if self.tool_history[-self.max_calls:] == self.tool_history[-2*self.max_calls:-self.max_calls]:
                    raise Exception(f'Tool loop detected: {tc.name} called {len(self.tool_history[-self.max_calls:])} times consecutively')

        if hasattr(step, 'handoff_to'):
            self.handoff_history.append(step.handoff_to.agent_id)
            recent_handoffs = self.handoff_history[-3:]
            if len(set(recent_handoffs)) < 2:
                raise Exception(f'Handoff loop detected between: {set(recent_handoffs)}')

# Usage
loop_detector = LoopDetector()
original_step = Runner.step
Runner.step = functools.partial(loop_detector.monitor_step, original_step)

from openai_agents import Runner
import re

def detect_state_loops(runner):
    state_history = []
    for i, step in enumerate(runner.trace):
        state_str = f"{step.agent_id}:{step.current_tool or 'none'}"
        state_history.append(state_str)

    # Look for repeating patterns of length 3+
    for length in range(3, min(10, len(state_history)//2 + 1)):
        for i in range(len(state_history) - 2*length):
            pattern = state_history[i:i+length]
            if state_history[i+length:i+2*length] == pattern:
                return {
                    'loop_detected': True,
                    'pattern': pattern,
                    'start_index': i,
                    'length': length
                }
    return {'loop_detected': False}

