from openai_agents import Agent

class LoopSafeAgent(Agent):
    def __init__(self, *args, recent_handoffs=None, **kwargs):
        super().__init__(*args, **kwargs)
        self.recent_handoffs = recent_handoffs or []

    def handoff_to(self, target_agent):
        # Prevent immediate handoff back to previous agent
        if (self.recent_handoffs and 
            target_agent.agent_id in self.recent_handoffs[-2:]):
            return self.final_output("Cannot handoff back immediately to avoid loops")

        self.recent_handoffs.append(self.agent_id)
        return super().handoff_to(target_agent)

# Usage
main_agent = LoopSafeAgent(name="Main", ...)
validator = LoopSafeAgent(name="Validator", recent_handoffs=[])

from openai_agents import Agent

class ProgressiveAgent(Agent):
    def __init__(self, *args, tool_usage_limits=None, **kwargs):
        super().__init__(*args, **kwargs)
        self.tool_usage = Counter()
        self.tool_limits = tool_usage_limits or {}

    def available_tools(self):
        available = super().available_tools()
        filtered = []
        for tool in available:
            usage = self.tool_usage[tool.name]
            limit = self.tool_limits.get(tool.name, 3)
            if usage < limit:
                filtered.append(tool)
        return filtered

    def after_tool_call(self, tool_name):
        self.tool_usage[tool_name] += 1

math_agent = ProgressiveAgent(
    tool_usage_limits={"calculator": 2, "web_search": 3}
)
